export const HARTHMERE_ALL_NPCS_V45 = [
  ...HARTHMERE_NAMED_NPCS_V44,
  ...HARTHMERE_REMAINING_NPCS_V45,
] as const;

export type HarthmereRemainingNpcV45 = (typeof HARTHMERE_REMAINING_NPCS_V45)[number];
export type HarthmereAnyNpcV45 = (typeof HARTHMERE_ALL_NPCS_V45)[number];

export const HARTHMERE_REMAINING_NPC_COVERAGE_POLICY_V45 = {
  version: "harthmere-remaining-npc-coverage-v45",
  v44NamedCount: 44,
  v45RemainingCount: HARTHMERE_REMAINING_NPCS_V45.length,
  includesAmbientPopulation: true,
  includesQuestOnlyNamedPeople: true,
  includesWildlifeAndMonsterFamilies: true,
  animalKindMustHaveNoWeapons: true,
  guardRolesMustHaveWeapons: true,
  everyNpcMustHaveHomeRouteStatsInventoryAndText: true,
} as const;

export function harthmereRemainingNpcActorAssetV45(npc: HarthmereRemainingNpcV45): string {
  return npc.spawn.asset;
}

export function harthmereRemainingNpcByIdV45(id: string): HarthmereRemainingNpcV45 | undefined {
  return HARTHMERE_REMAINING_NPCS_V45.find((npc) => npc.id === id);
}
